/**
 * Fire Toolshed — shared report logo (Benham / MeadHunt JV / Haskell-by-state / upload).
 * Persists selection in localStorage so all report tools stay in sync.
 * Benham: shared/logos/benham.png (embedded data URL).
 * MeadHunt JV: shared/logos/meadhunt-jv.png (embedded data URL).
 * Haskell: entity lockup by US state (business card cheat sheet 06/27/2025).
 * Diamond mark is brand-style vector (#0069AA + solid white H) for sharp print.
 */
(function (global) {
  "use strict";

  var STORAGE_KEY = "fireToolshed.reportLogo.v1";
  var MAX_UPLOAD_BYTES = 900 * 1024;

  /**
   * Haskell legal entities → logo tagline (business card cheat sheet).
   * id used for SVG generation.
   */
  var HASKELL_ENTITIES = {
    company: {
      id: "company",
      name: "The Haskell Company",
      tagline: "The Haskell Company",
    },
    aei: {
      id: "aei",
      name: "Haskell Architecture and Engineering, Inc.",
      tagline: "Architecture and Engineering, Inc.",
    },
    pa: {
      id: "pa",
      name: "Haskell Architects and Engineers, PA",
      tagline: "Architects and Engineers, PA",
    },
    pa_inc: {
      id: "pa_inc",
      name: "Haskell Architects and Engineers, P.A., INC.",
      tagline: "Architects and Engineers, P.A., INC.",
    },
    pc: {
      id: "pc",
      name: "Haskell Architects and Engineers, P.C.",
      tagline: "Architects and Engineers, P.C.",
    },
    pa_pc: {
      id: "pa_pc",
      name: "Haskell Architects and Engineers, P.A., P.C.",
      tagline: "Architects and Engineers, P.A., P.C.",
    },
    hae: {
      id: "hae",
      name: "Haskell HAE, P.A.",
      tagline: "HAE, P.A.",
    },
  };

  /**
   * State code → entity id (from "Distributing Business Cards - Haskell Entities/Logos by State").
   * Unlisted codes fall back to aei.
   */
  var HASKELL_STATE_ENTITY = {
    // The Haskell Company
    FL: "company",
    OK: "company",
    MO: "company",
    TX: "company",
    ND: "company",
    UT: "company",
    WA: "company",
    // Architecture and Engineering, Inc.
    AK: "aei",
    HI: "aei",
    ME: "aei",
    SC: "aei",
    AZ: "aei",
    ID: "aei",
    MD: "aei",
    SD: "aei",
    AR: "aei",
    IL: "aei",
    MA: "aei",
    TN: "aei",
    CA: "aei",
    IN: "aei",
    MI: "aei",
    VT: "aei",
    CO: "aei",
    IA: "aei",
    MT: "aei",
    VA: "aei",
    DE: "aei",
    KS: "aei",
    NE: "aei",
    WV: "aei",
    DC: "aei",
    KY: "aei",
    NH: "aei",
    WI: "aei",
    GA: "aei",
    LA: "aei",
    NM: "aei",
    WY: "aei",
    OR: "aei",
    // Architects and Engineers, PA
    MN: "pa",
    NJ: "pa",
    NC: "pa",
    OH: "pa",
    RI: "pa",
    // PA/PC individual variations
    AL: "pa_inc",
    CT: "pc",
    PA: "pc",
    NY: "pa_pc",
    MS: "hae",
    NV: "hae",
  };

  /** States shown in selector (cheat sheet + remaining US for completeness). */
  var HASKELL_STATES = [
    { code: "AL", name: "Alabama" },
    { code: "AK", name: "Alaska" },
    { code: "AZ", name: "Arizona" },
    { code: "AR", name: "Arkansas" },
    { code: "CA", name: "California" },
    { code: "CO", name: "Colorado" },
    { code: "CT", name: "Connecticut" },
    { code: "DE", name: "Delaware" },
    { code: "DC", name: "District of Columbia" },
    { code: "FL", name: "Florida" },
    { code: "GA", name: "Georgia" },
    { code: "HI", name: "Hawaii" },
    { code: "ID", name: "Idaho" },
    { code: "IL", name: "Illinois" },
    { code: "IN", name: "Indiana" },
    { code: "IA", name: "Iowa" },
    { code: "KS", name: "Kansas" },
    { code: "KY", name: "Kentucky" },
    { code: "LA", name: "Louisiana" },
    { code: "ME", name: "Maine" },
    { code: "MD", name: "Maryland" },
    { code: "MA", name: "Massachusetts" },
    { code: "MI", name: "Michigan" },
    { code: "MN", name: "Minnesota" },
    { code: "MS", name: "Mississippi" },
    { code: "MO", name: "Missouri" },
    { code: "MT", name: "Montana" },
    { code: "NE", name: "Nebraska" },
    { code: "NV", name: "Nevada" },
    { code: "NH", name: "New Hampshire" },
    { code: "NJ", name: "New Jersey" },
    { code: "NM", name: "New Mexico" },
    { code: "NY", name: "New York" },
    { code: "NC", name: "North Carolina" },
    { code: "ND", name: "North Dakota" },
    { code: "OH", name: "Ohio" },
    { code: "OK", name: "Oklahoma" },
    { code: "OR", name: "Oregon" },
    { code: "PA", name: "Pennsylvania" },
    { code: "RI", name: "Rhode Island" },
    { code: "SC", name: "South Carolina" },
    { code: "SD", name: "South Dakota" },
    { code: "TN", name: "Tennessee" },
    { code: "TX", name: "Texas" },
    { code: "UT", name: "Utah" },
    { code: "VT", name: "Vermont" },
    { code: "VA", name: "Virginia" },
    { code: "WA", name: "Washington" },
    { code: "WV", name: "West Virginia" },
    { code: "WI", name: "Wisconsin" },
    { code: "WY", name: "Wyoming" },
  ];

  function entityForState(code) {
    var c = String(code || "").toUpperCase();
    var id = HASKELL_STATE_ENTITY[c] || "aei";
    return HASKELL_ENTITIES[id] || HASKELL_ENTITIES.aei;
  }

  function stateName(code) {
    var c = String(code || "").toUpperCase();
    for (var i = 0; i < HASKELL_STATES.length; i++) {
      if (HASKELL_STATES[i].code === c) return HASKELL_STATES[i].name;
    }
    return c || "—";
  }

  /**
   * Wordmark lockup approximating business-card logos:
   * blue diamond mark + HASKELL + entity tagline.
   */
  /**
   * Wordmark lockup: official blue diamond H mark + HASKELL + entity tagline.
   * Crisp vector diamond (brand blue #0069AA + solid white H) — not the old stroke/pixel approximation.
   */
  function haskellLogoDataUrl(entity) {
    entity = entity || HASKELL_ENTITIES.aei;
    var tag = escapeXml(entity.tagline || "");
    var aria = escapeXml("Haskell — " + (entity.name || ""));
    // Wider canvas for longer taglines (e.g. P.A., INC.)
    var w = Math.max(360, 100 + Math.ceil(tag.length * 6.6));
    // Diamond mark in a 64×64 tile; pure vector for sharp print at any size
    var mark =
      '<g transform="translate(4,4)">' +
      '<path fill="#0069AA" d="M32 0L64 32 32 64 0 32z"/>' +
      // Solid white H (axis-aligned; proportions match brand graphic)
      '<path fill="#FFFFFF" d="M19.2 17.3h8v11.2h9.6V17.3h8v29.4h-8V35.5h-9.6v11.2h-8z"/>' +
      "</g>";
    var svg =
      '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' +
      w +
      ' 72" role="img" aria-label="' +
      aria +
      '">' +
      mark +
      '<text x="78" y="38" font-family="Arial Black, Arial, Helvetica, sans-serif" font-size="28" font-weight="900" fill="#0f172a" letter-spacing="0.06em">HASKELL</text>' +
      '<text x="78" y="56" font-family="Arial, Helvetica, sans-serif" font-size="10.5" font-weight="600" fill="#0069AA">' +
      tag +
      "</text>" +
      "</svg>";
    return "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
  }
  function escapeXml(s) {
    return String(s == null ? "" : s)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  /** Brand PNG data URLs (embedded for offline print / save HTML). */
  var BENHAM_DATA_URL = "data:image/png;base64,";
  var MEADHUNT_DATA_URL = "data:image/png;base64,";

  var BUILTIN = {
    benham: {
      label: "Benham",
      file: "benham.png",
      get dataUrl() {
        return BENHAM_DATA_URL;
      },
    },
    meadhunt: {
      label: "MeadHunt JV",
      file: "meadhunt-jv.png",
      get dataUrl() {
        return MEADHUNT_DATA_URL;
      },
    },
  };

  var LOGO_SOURCES = {
    benham: true,
    meadhunt: true,
    haskell: true,
    upload: true,
  };

  function defaultState() {
    return {
      source: "benham",
      /** US state code for Haskell entity lockup */
      haskellState: "FL",
      uploadDataUrl: "",
      uploadName: "",
      updatedAt: "",
    };
  }

  function normalizeSource(src) {
    src = String(src || "").toLowerCase();
    return LOGO_SOURCES[src] ? src : "benham";
  }

  function normalizeStateCode(code) {
    var c = String(code || "").toUpperCase().trim();
    if (HASKELL_STATE_ENTITY[c] || HASKELL_STATES.some(function (s) { return s.code === c; })) {
      return c;
    }
    return "FL";
  }

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return defaultState();
      var d = JSON.parse(raw);
      if (!d || typeof d !== "object") return defaultState();
      return {
        source: normalizeSource(d.source),
        haskellState: normalizeStateCode(d.haskellState || "FL"),
        uploadDataUrl: typeof d.uploadDataUrl === "string" ? d.uploadDataUrl : "",
        uploadName: typeof d.uploadName === "string" ? d.uploadName : "",
        updatedAt: d.updatedAt || "",
      };
    } catch (_) {
      return defaultState();
    }
  }

  function save(state) {
    var s = Object.assign(defaultState(), state || {}, {
      haskellState: normalizeStateCode((state && state.haskellState) || "FL"),
      updatedAt: new Date().toISOString(),
    });
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(s));
    } catch (_) {
      /* quota / private mode */
    }
    return s;
  }

  function getHaskellEntity(st) {
    st = st || load();
    return entityForState(st.haskellState);
  }

  function getLogoSrc(opts) {
    var st = load();
    if (st.source === "upload") {
      return st.uploadDataUrl || "";
    }
    if (st.source === "haskell") {
      return haskellLogoDataUrl(getHaskellEntity(st));
    }
    if (st.source === "meadhunt") return MEADHUNT_DATA_URL || "";
    if (st.source === "benham") return BENHAM_DATA_URL || "";
    return "";
  }

  function getSourceLabel() {
    var st = load();
    if (st.source === "upload") {
      return st.uploadName ? "Custom: " + st.uploadName : "Custom upload";
    }
    if (st.source === "haskell") {
      var ent = getHaskellEntity(st);
      return (
        "Haskell — " +
        stateName(st.haskellState) +
        " (" +
        (ent.tagline || ent.name) +
        ")"
      );
    }
    if (st.source === "meadhunt") return "MeadHunt JV";
    if (st.source === "benham") return "Benham";
    return "";
  }

  function reportHeaderHtml(opts) {
    opts = opts || {};
    var maxH = opts.maxHeight || 56;
    var cls = opts.className || "report-logo";
    var src = getLogoSrc();
    if (!src) return "";
    var label = getSourceLabel();
    return (
      '<div class="' +
      cls +
      '" style="margin:0 0 1rem 0;display:flex;align-items:center;justify-content:space-between;gap:1rem;border-bottom:1px solid #e2e8f0;padding-bottom:0.75rem">' +
      '<img src="' +
      src +
      '" alt="' +
      escapeAttr(label || "Company logo") +
      '" style="max-height:' +
      maxH +
      'px;max-width:280px;width:auto;height:auto;object-fit:contain"/>' +
      '<span style="font-size:0.75rem;color:#64748b;text-align:right;max-width:12rem">' +
      escapeHtml(label) +
      "</span>" +
      "</div>"
    );
  }

  function escapeHtml(s) {
    return String(s)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function escapeAttr(s) {
    return escapeHtml(s).replace(/'/g, "&#39;");
  }

  function applyPreview(previewEl) {
    if (!previewEl) return;
    var src = getLogoSrc();
    var st = load();
    if (!src) {
      previewEl.innerHTML =
        '<span class="sub" style="color:#64748b">No logo selected</span>';
      return;
    }
    var extra = "";
    if (st.source === "upload" && st.uploadName) {
      extra =
        '<span class="sub" style="display:block;margin-top:0.25rem">' +
        escapeHtml(st.uploadName) +
        "</span>";
    } else if (st.source === "haskell") {
      var ent = getHaskellEntity(st);
      extra =
        '<span class="sub" style="display:block;margin-top:0.25rem">' +
        escapeHtml(stateName(st.haskellState) + " → " + ent.name) +
        "</span>";
    }
    previewEl.innerHTML =
      '<img src="' +
      src +
      '" alt="Logo preview" style="max-height:48px;max-width:240px;object-fit:contain;display:block"/>' +
      extra;
  }

  function stateOptionsHtml(selected) {
    selected = normalizeStateCode(selected || "FL");
    return HASKELL_STATES.map(function (s) {
      var ent = entityForState(s.code);
      return (
        '<option value="' +
        s.code +
        '"' +
        (s.code === selected ? " selected" : "") +
        ">" +
        escapeHtml(s.name) +
        " — " +
        escapeHtml(ent.tagline) +
        "</option>"
      );
    }).join("");
  }

  /**
   * Ensure Haskell state selector exists next to logo controls.
   */
  function ensureHaskellStateUi(selectEl, cfg) {
    var wrapId = cfg.stateWrapId || "reportLogoHaskellStateWrap";
    var stateId = cfg.stateSelectId || "reportLogoHaskellState";
    var wrap = document.getElementById(wrapId);
    if (!wrap && selectEl && selectEl.parentNode) {
      wrap = document.createElement("div");
      wrap.id = wrapId;
      wrap.className = "hidden";
      wrap.style.marginTop = "0.5rem";
      wrap.innerHTML =
        '<label for="' +
        stateId +
        '" class="sub" style="display:block;font-weight:700;margin-bottom:0.25rem">Haskell logo — project state</label>' +
        '<select id="' +
        stateId +
        '" style="width:100%;min-height:2.5rem;padding:0.45rem 0.65rem;border:1px solid #e2e8f0;border-radius:0.65rem;background:#f8fafc">' +
        stateOptionsHtml(load().haskellState) +
        "</select>" +
        '<span class="sub" style="display:block;margin-top:0.3rem;font-size:0.75rem;color:#64748b">' +
        "Selects the Haskell legal-entity lockup for that state (business card / logo by state). Appears on print and saved reports." +
        "</span>";
      // Insert after logo select (or after file wrap if present)
      var insertAfter = selectEl;
      if (cfg.fileWrapId) {
        var fw = document.getElementById(cfg.fileWrapId);
        if (fw) insertAfter = fw;
      }
      if (insertAfter.nextSibling) {
        insertAfter.parentNode.insertBefore(wrap, insertAfter.nextSibling);
      } else {
        insertAfter.parentNode.appendChild(wrap);
      }
    } else if (wrap) {
      var sel = document.getElementById(stateId);
      if (sel && !sel.options.length) {
        sel.innerHTML = stateOptionsHtml(load().haskellState);
      }
    }
    return {
      wrap: document.getElementById(wrapId),
      select: document.getElementById(stateId),
    };
  }

  function bindControls(cfg) {
    cfg = cfg || {};
    var select = document.getElementById(cfg.selectId);
    if (!select) return;
    var file = cfg.fileId ? document.getElementById(cfg.fileId) : null;
    var preview = cfg.previewId ? document.getElementById(cfg.previewId) : null;
    var fileWrap = cfg.fileWrapId ? document.getElementById(cfg.fileWrapId) : null;
    var hs = ensureHaskellStateUi(select, cfg);

    function syncUi() {
      var st = load();
      select.value = normalizeSource(st.source);
      if (fileWrap) {
        if (st.source === "upload") fileWrap.classList.remove("hidden");
        else fileWrap.classList.add("hidden");
      }
      if (hs.wrap) {
        if (st.source === "haskell") hs.wrap.classList.remove("hidden");
        else hs.wrap.classList.add("hidden");
      }
      if (hs.select) {
        hs.select.value = normalizeStateCode(st.haskellState);
      }
      applyPreview(preview);
    }

    select.addEventListener("change", function () {
      var st = load();
      st.source = normalizeSource(select.value);
      save(st);
      if (st.source === "upload" && file) {
        if (fileWrap) fileWrap.classList.remove("hidden");
        if (!st.uploadDataUrl) {
          try {
            file.click();
          } catch (_) { /* ignore */ }
        }
      } else if (fileWrap) {
        fileWrap.classList.add("hidden");
      }
      if (hs.wrap) {
        if (st.source === "haskell") hs.wrap.classList.remove("hidden");
        else hs.wrap.classList.add("hidden");
      }
      applyPreview(preview);
      if (typeof cfg.onChange === "function") cfg.onChange(load());
    });

    if (hs.select) {
      hs.select.addEventListener("change", function () {
        var st = load();
        st.source = "haskell";
        st.haskellState = normalizeStateCode(hs.select.value);
        save(st);
        select.value = "haskell";
        if (hs.wrap) hs.wrap.classList.remove("hidden");
        applyPreview(preview);
        if (typeof cfg.onChange === "function") cfg.onChange(load());
      });
    }

    if (file) {
      file.addEventListener("change", function () {
        var f = file.files && file.files[0];
        if (!f) return;
        if (!/^image\//i.test(f.type)) {
          alert("Please choose an image file (PNG, JPG, SVG, or WebP).");
          file.value = "";
          return;
        }
        if (f.size > MAX_UPLOAD_BYTES) {
          alert("Image is too large (max ~900 KB). Compress or use a smaller logo.");
          file.value = "";
          return;
        }
        var reader = new FileReader();
        reader.onload = function () {
          var st = load();
          st.source = "upload";
          st.uploadDataUrl = String(reader.result || "");
          st.uploadName = f.name || "logo";
          save(st);
          select.value = "upload";
          if (fileWrap) fileWrap.classList.remove("hidden");
          if (hs.wrap) hs.wrap.classList.add("hidden");
          applyPreview(preview);
          if (typeof cfg.onChange === "function") cfg.onChange(load());
        };
        reader.onerror = function () {
          alert("Could not read that image file.");
        };
        reader.readAsDataURL(f);
      });
    }

    syncUi();
    return { refresh: syncUi, load: load };
  }

  function fieldHtml(ids) {
    ids = ids || {};
    var sid = ids.selectId || "reportLogoSource";
    var fid = ids.fileId || "reportLogoFile";
    var pid = ids.previewId || "reportLogoPreview";
    var wid = ids.fileWrapId || "reportLogoFileWrap";
    var sw = ids.stateWrapId || "reportLogoHaskellStateWrap";
    var ss = ids.stateSelectId || "reportLogoHaskellState";
    return (
      '<div class="field" style="grid-column:1/-1">' +
      '<label for="' +
      sid +
      '">Report logo</label>' +
      '<select id="' +
      sid +
      '">' +
      '<option value="benham">Benham</option>' +
      '<option value="meadhunt">MeadHunt JV</option>' +
      '<option value="haskell">Haskell (by state)</option>' +
      '<option value="upload">Upload image…</option>' +
      "</select>" +
      '<span class="sub">Appears on print and saved HTML. Benham, MeadHunt JV, or Haskell (by state); selection is shared across Toolshed report tools.</span>' +
      '<div id="' +
      sw +
      '" class="hidden" style="margin-top:0.5rem">' +
      '<label for="' +
      ss +
      '" class="sub" style="display:block;font-weight:700;margin-bottom:0.25rem">Haskell logo — project state</label>' +
      '<select id="' +
      ss +
      '">' +
      stateOptionsHtml("FL") +
      "</select>" +
      '<span class="sub" style="display:block;margin-top:0.3rem">Legal-entity lockup per Haskell business-card / logo-by-state guide.</span>' +
      "</div>" +
      '<div id="' +
      wid +
      '" class="hidden" style="margin-top:0.5rem">' +
      '<label for="' +
      fid +
      '" class="sub" style="display:block;margin-bottom:0.25rem">Choose logo image</label>' +
      '<input id="' +
      fid +
      '" type="file" accept="image/png,image/jpeg,image/svg+xml,image/webp,image/*" />' +
      "</div>" +
      '<div id="' +
      pid +
      '" style="margin-top:0.5rem;min-height:2rem"></div>' +
      "</div>"
    );
  }

  global.FireToolshedLogo = {
    STORAGE_KEY: STORAGE_KEY,
    BUILTIN: BUILTIN,
    HASKELL_ENTITIES: HASKELL_ENTITIES,
    HASKELL_STATE_ENTITY: HASKELL_STATE_ENTITY,
    HASKELL_STATES: HASKELL_STATES,
    entityForState: entityForState,
    haskellLogoDataUrl: haskellLogoDataUrl,
    load: load,
    save: save,
    getLogoSrc: getLogoSrc,
    getSourceLabel: getSourceLabel,
    getHaskellEntity: getHaskellEntity,
    reportHeaderHtml: reportHeaderHtml,
    bindControls: bindControls,
    fieldHtml: fieldHtml,
    applyPreview: applyPreview,
    /** Used by embed script */
    setBenhamDataUrl: function (url) {
      BENHAM_DATA_URL = url || "";
    },
    setMeadhuntDataUrl: function (url) {
      MEADHUNT_DATA_URL = url || "";
    },
  };
})(typeof window !== "undefined" ? window : globalThis);
